import { createContext, useContext, useState, useEffect } from 'react';
import { api } from '../services/api';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Check local storage for persisted login
        const storedUser = localStorage.getItem('ai_edu_user');
        if (storedUser) {
            setUser(JSON.parse(storedUser));
        }
        setLoading(false);
    }, []);

    const login = async (email, password) => {
        const userData = await api.auth.login(email, password);
        setUser(userData);
        localStorage.setItem('ai_edu_user', JSON.stringify(userData));
        return userData;
    };

    const register = async (name, email, password) => {
        const userData = await api.auth.register(name, email, password);
        setUser(userData);
        localStorage.setItem('ai_edu_user', JSON.stringify(userData));
        return userData;
    };

    const logout = () => {
        setUser(null);
        localStorage.removeItem('ai_edu_user');
        api.auth.logout();
    };

    return (
        <AuthContext.Provider value={{ user, login, register, logout, loading, isAuthenticated: !!user }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

import { createContext, useContext, useState, useEffect } from 'react';

const ThemeContext = createContext(null);

const getInitialTheme = () => {
    // 1. Check localStorage
    const stored = localStorage.getItem('ai_edu_theme');
    if (stored === 'dark' || stored === 'light') return stored;

    return 'light';
};

export const ThemeProvider = ({ children }) => {
    const [theme, setThemeState] = useState(getInitialTheme);

    // Apply the dark class to <html> whenever theme changes
    useEffect(() => {
        const root = document.documentElement;
        const favicon = document.querySelector('link[rel="icon"]');

        if (theme === 'dark') {
            root.classList.add('dark');
            if (favicon) favicon.href = '/favicon-dark.png';
        } else {
            root.classList.remove('dark');
            if (favicon) favicon.href = '/favicon-light.png';
        }
        localStorage.setItem('ai_edu_theme', theme);
    }, [theme]);

    const toggleTheme = () => {
        setThemeState((prev) => (prev === 'dark' ? 'light' : 'dark'));
    };

    const setTheme = (newTheme) => {
        setThemeState(newTheme);
    };

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme, setTheme }}>
            {children}
        </ThemeContext.Provider>
    );
};

export const useTheme = () => {
    const context = useContext(ThemeContext);
    if (!context) {
        throw new Error('useTheme must be used within a ThemeProvider');
    }
    return context;
};

