    const [bio, setBio] = useState('');

    const [currentPassword, setCurrentPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');

    const [isSavingProfile, setIsSavingProfile] = useState(false);
    const [isSavingPassword, setIsSavingPassword] = useState(false);

    const handleSaveProfile = (e) => {
        e.preventDefault();
        setIsSavingProfile(true);
        setTimeout(() => {
            setIsSavingProfile(false);
            alert('Profile updated successfully!');
        }, 1000);
    };

    const handleUpdatePassword = (e) => {
        e.preventDefault();
        if (newPassword !== confirmPassword) {
            alert('New passwords do not match!');
            return;
        }
        setIsSavingPassword(true);
        setTimeout(() => {
            setIsSavingPassword(false);
            alert('Password updated successfully!');
            setCurrentPassword('');
            setNewPassword('');
            setConfirmPassword('');
        }, 1000);
    };

    return (
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8 transition-colors duration-300">
            <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="mb-8"
            >
                <h1 className="text-2xl sm:text-3xl font-bold text-slate-900 dark:text-white">Profile Settings</h1>
                <p className="text-slate-500 dark:text-slate-400 mt-2">Manage your personal information and security.</p>
            </motion.div>

            <div className="space-y-6">
                {/* Profile Picture Section */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.1 }}
                    className="bg-white dark:bg-slate-900 p-6 sm:p-8 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800"
                >
                    <h2 className="text-xl font-bold text-slate-900 dark:text-white mb-6 flex items-center gap-2">
                        <User className="text-primary w-5 h-5" /> Profile Picture
                    </h2>
                    <div className="flex flex-col sm:flex-row items-start sm:items-center gap-6">
                        <div className="relative">
                            <img
                                src={user?.avatar || "https://ui-avatars.com/api/?name=" + (user?.name || "User") + "&background=random"}
                                alt="Profile"
                                className="w-24 h-24 sm:w-32 sm:h-32 rounded-full object-cover border-4 border-slate-100 dark:border-slate-800"
                            />
                            <button className="absolute bottom-0 right-0 sm:bottom-2 sm:right-2 p-2 bg-primary text-white rounded-full hover:bg-primary-600 transition-colors shadow-md">
                                <Camera size={16} />
                            </button>
                        </div>
                        <div>
                            <div className="flex flex-wrap gap-3 mb-3">
                                <Button size="sm">Upload New Photo</Button>
                                <Button variant="outline" size="sm" className="text-red-500 hover:text-red-600 border-red-200 hover:border-red-300 dark:border-red-900/30 dark:hover:border-red-800/50">Remove</Button>
                            </div>
                            <p className="text-sm text-slate-500 dark:text-slate-400">
                                Recommended size: 400x400px. JPG, PNG or GIF up to 5MB.
                            </p>
                        </div>
                    </div>
                </motion.div>

                {/* Personal Information */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="bg-white dark:bg-slate-900 p-6 sm:p-8 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800"
                >
                    <h2 className="text-xl font-bold text-slate-900 dark:text-white mb-6 flex items-center gap-2">
                        <Mail className="text-primary w-5 h-5" /> Personal Information
                    </h2>
                    <form onSubmit={handleSaveProfile} className="space-y-4">
                        <div className="grid grid-cols-1 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Full Name</label>
                                <input
                                    type="text"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all outline-none"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Email Address</label>
                                <input
                                    type="email"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all outline-none"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Bio</label>
                                <textarea
                                    value={bio}
                                    onChange={(e) => setBio(e.target.value)}
                                    rows="3"
                                    placeholder="Tell us a little about yourself"
                                    className="w-full px-4 py-2 border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all outline-none resize-none"
                                />
                            </div>
                        </div>
                        <div className="flex justify-end pt-4">
                            <Button type="submit" disabled={isSavingProfile}>
                                {isSavingProfile ? 'Saving...' : <><Save size={16} className="mr-2" /> Save Changes</>}
                            </Button>
                        </div>
                    </form>
                </motion.div>

                {/* Password & Security */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                    className="bg-white dark:bg-slate-900 p-6 sm:p-8 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800"
                >
                    <h2 className="text-xl font-bold text-slate-900 dark:text-white mb-6 flex items-center gap-2">
                        <Shield className="text-primary w-5 h-5" /> Password & Security
                    </h2>
                    <form onSubmit={handleUpdatePassword} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Current Password</label>
                            <div className="relative">
                                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                                    <Lock size={16} />
                                </span>
                                <input
                                    type="password"
                                    value={currentPassword}
                                    onChange={(e) => setCurrentPassword(e.target.value)}
                                    className="w-full pl-10 pr-4 py-2 border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all outline-none"
                                    placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                    required
                                />
                            </div>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">New Password</label>
                                <div className="relative">
                                    <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                                        <Lock size={16} />
                                    </span>
                                    <input
                                        type="password"
                                        value={newPassword}
                                        onChange={(e) => setNewPassword(e.target.value)}
                                        className="w-full pl-10 pr-4 py-2 border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all outline-none"
                                        placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                        required
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Confirm New Password</label>
                                <div className="relative">
                                    <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                                        <Lock size={16} />
                                    </span>
                                    <input
                                        type="password"
                                        value={confirmPassword}
                                        onChange={(e) => setConfirmPassword(e.target.value)}
                                        className="w-full pl-10 pr-4 py-2 border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-primary/50 focus:border-primary transition-all outline-none"
                                        placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                        required
                                    />
                                </div>
                            </div>
                        </div>
                        <div className="flex justify-end pt-4">
                            <Button type="submit" disabled={isSavingPassword || !currentPassword || !newPassword || !confirmPassword}>
                                {isSavingPassword ? 'Updating...' : 'Update Password'}
                            </Button>
                        </div>
                    </form>
                </motion.div>
            </div>
        </div>
    );
};

export default LearnerProfilePage;

/**
 * API Service Layer
 * -----------------
 * This file is the SINGLE integration point for all backend API calls.
 * Currently uses mock data from src/data/mockData.js.
 * 
 * TO INTEGRATE WITH BACKEND:
 * 1. Replace the mock implementations with fetch/axios calls
 * 2. Update BASE_URL to your backend URL
 * 3. Add token from localStorage to Authorization header
 * 
 * Example:
 *   const BASE_URL = 'https://your-api.com/api';
 *   const headers = () => ({
 *     'Content-Type': 'application/json',
 *     'Authorization': `Bearer ${localStorage.getItem('ai_edu_token')}`
 *   });
 */

import { courses, categories, testimonials } from '../data/mockData';

// Simulated network delay
const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

export const api = {
    // ΓöÇΓöÇΓöÇ Course Endpoints ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Backend: GET /api/courses
    courses: {
        /**
         * Get all courses
         * Backend: GET /api/courses?category=X&search=Y
         * Response: Course[]
         */
        getAll: async (filters = {}) => {
            await delay(600);
            let result = [...courses];
            if (filters.category && filters.category !== 'All') {
                result = result.filter(c => c.category === filters.category);
            }
            if (filters.search) {
                result = result.filter(c =>
                    c.title.toLowerCase().includes(filters.search.toLowerCase())
                );
            }
            return result;
        },

        /**
         * Get single course by ID
         * Backend: GET /api/courses/:id
         * Response: Course (with curriculum, reviews)
         */
        getById: async (id) => {
            await delay(600);
            const course = courses.find((c) => c.id === parseInt(id));
            if (!course) throw new Error('Course not found');
            return course;
        },

        /**
         * Get available categories
         * Backend: GET /api/categories
         * Response: Category[]
         */
        getCategories: async () => {
            await delay(400);
            return categories;
        },
    },

    // ΓöÇΓöÇΓöÇ Learner Endpoints ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Backend: GET /api/learner/*
    learner: {
        /**
         * Get enrolled courses with progress
         * Backend: GET /api/learner/progress
         * Headers: Authorization: Bearer <token>
         * Response: { courseId, title, progress, lastLesson }[]
         */
        getProgress: async () => {
            await delay(500);
            return [
                {
                    courseId: 1,
                    title: 'Machine Learning Fundamentals',
                    progress: 65,
                    lastLesson: 'Lecture 14: Gradient Descent',
                    image: 'https://images.unsplash.com/photo-1527474305487-b87b222841cc?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80'
                },
                {
                    courseId: 2,
                    title: 'Advanced React Patterns',
                    progress: 45,
                    lastLesson: 'Lesson 5: Higher Order Components',
                    image: 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80'
                },
            ];
        },

        /**
         * Get learner stats
         * Backend: GET /api/learner/stats
         * Response: { hoursWatched, certificates, coursesInProgress }
         */
        getStats: async () => {
            await delay(500);
            return {
                hoursWatched: 12,
                certificates: 2,
                coursesInProgress: 4
            };
        },

        /**
         * Get recommended courses for this learner
         * Backend: GET /api/learner/recommendations
         * Response: Course[] (based on AI/ML analysis)
         */
        getRecommendations: async () => {
            await delay(600);
            return courses.slice(0, 3);
        },
    },

    // ΓöÇΓöÇΓöÇ Instructor Endpoints ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Backend: GET /api/instructor/*
    instructor: {
        /**
         * Get instructor dashboard stats
         * Backend: GET /api/instructor/stats
         * Response: { totalStudents, totalRevenue, avgRating, activeCourses }
         */
        getStats: async () => {
            await delay(500);
            return {
                totalStudents: 1234,
                totalRevenue: '$12.5k',
                avgRating: 4.8,
                totalReviews: 500,
                activeCourses: 8,
                pendingReview: 2
            };
        },

        /**
         * Get instructor's courses
         * Backend: GET /api/instructor/courses
         * Response: InstructorCourse[]
         */
        getCourses: async () => {
            await delay(600);
            return [
                { id: 1, title: 'Introduction to AI v1.0', students: 120, status: 'Published', revenue: '$1,200' },
                { id: 2, title: 'Introduction to AI v2.0', students: 85, status: 'Published', revenue: '$950' },
                { id: 3, title: 'Introduction to AI v3.0', students: 200, status: 'Draft', revenue: '$0' },
            ];
        },
    },

    // ΓöÇΓöÇΓöÇ Admin Endpoints ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Backend: GET /api/admin/*
    admin: {
        /**
         * Get admin dashboard stats
         * Backend: GET /api/admin/stats
         * Response: { totalUsers, activeCourses, totalRevenue, activeUsers }
         */
        getStats: async () => {
            await delay(500);
            return {
                totalUsers: 12345,
                activeCourses: courses.length,
                totalRevenue: 45678,
                activeUsers: 890
            };
        },

        /**
         * Get all users (admin)
         * Backend: GET /api/admin/users?page=X&limit=Y
         * Response: { users: User[], total: number }
         */
        getUsers: async () => {
            await delay(600);
            return [
                { id: 1, name: 'Alice Smith', email: 'alice@example.com', role: 'learner', joined: '2023-10-15' },
                { id: 2, name: 'Bob Jones', email: 'bob@example.com', role: 'learner', joined: '2023-11-02' },
                { id: 3, name: 'Charlie Kim', email: 'charlie@example.com', role: 'instructor', joined: '2023-09-01' },
                { id: 4, name: 'David Lee', email: 'david@example.com', role: 'learner', joined: '2023-12-10' },
                { id: 5, name: 'Emma Wilson', email: 'emma@example.com', role: 'admin', joined: '2024-01-05' },
            ];
        },
    },

    // ΓöÇΓöÇΓöÇ AI Chat Endpoints ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Backend: POST /api/ai/chat
    ai: {
        /**
         * Send message to AI tutor
         * Backend: POST /api/ai/chat
         * Body: { message, context?: { courseId, videoTimestamp } }
         * Response: { response: string }
         */
        chat: async (message, context = {}) => {
            await delay(1500);
            return {
                response: `I analyzed your question: "${message}". Based on the current context, here is a detailed explanation...`
            };
        }
    },

    // ΓöÇΓöÇΓöÇ Testimonials ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    testimonials: {
        getAll: async () => {
            await delay(300);
            return testimonials;
        }
    }
};
